import ldap3
from ldap3 import Server, Connection, AUTO_BIND_NO_TLS

def search_user(username):
    try:
        server = Server('ldap.example.com', port=389)
        conn = Connection(server, user='cn=admin,dc=example,dc=com', password='password')
        
        if not conn.bind():
            print("LDAP connection failed")
            return None
        
        filter = f'(uid={username})'
        attributes = ['*']
        
        result = conn.search(search_base='dc=example,dc=com', search_filter=filter, 
                             search_scope='SUBTREE', attributes=attributes)
        
        if result:
            user_data = {}
            for entry in conn.response:
                user_data[entry['dn']] = entry
            return user_data
        else:
            print(f"No user found with username: {username}")
            return None
    
    except ldap3.core.exceptions.LDAPException as e:
        print(f"LDAP error: {e}")
        return None

